// Option A: Products self-configure (most common)
class EmailNotification implements Notification {
    EmailNotification() {
        this.config = SmtpConfig.load(); // I load my own config
    }
}

// Option B: Factory Method -- each subclass owns its config
class EmailNotificationService extends NotificationService {
    Notification createNotification() {
        SmtpConfig config = loadSmtpConfig(); // my private knowledge
        return new EmailNotification(config);
    }
}

// Option C: Generic config map
Notification n = factory.create(type, Map.of("host", "smtp.gmail.com"));

// Framework: each team instantiates their own creator
PaymentService service = new UPIPaymentService(); // no if-else

// Standalone app: Simple Factory on top to select
PaymentService service = ServiceFactory.create("upi");

// Spring DI: framework handles everything
@Autowired Map<String, PaymentService> services;
PaymentService service = services.get("upi"); // runtime, zero 'new'

@Configuration
class NotificationConfig {
    @Bean("email") // THIS is a factory method!
    Notification email() {
        return new EmailNotification(loadSmtpConfig());
    }

    @Bean("sms")
    Notification sms() {
        return new SMSNotification(loadApiKey());
    }
}

// Client: @Autowired IS the factory call
@Autowired Map<String, Notification> notifications;
notifications.get("email").send(msg); // Spring did the factory work

// Strategy: WHICH algorithm to run (behavior swapping)
notificationService.setStrategy(new EmailStrategy());
notificationService.send(msg); // strategy decides HOW to send

// Factory: WHICH object to create (creation selection)
Notification n = NotificationFactory.create("EMAIL");
n.send(msg); // factory decided WHICH object to create

// They combine: Factory CREATES the Strategy object
Strategy s = StrategyFactory.create(userChoice);
context.setStrategy(s);

// Simple Factory: factory IS a separate class
class NotificationFactory {
    static Notification create(Type t) {
        return switch(t) { EMAIL -> new Email(); SMS -> new SMS(); };
    }
}

// Factory Method: factory IS a method INSIDE the service
abstract class NotificationService {
    abstract Notification createNotification(); // <-- THIS is the "factory"
    void send(String msg) {
        Notification n = createNotification(); // calls the factory method
        n.send(msg);
        log(msg);  // shared orchestration -- the reason this class exists
    }
}

// WRONG: forces India = UPI (false coupling)
class IndiaPaymentFactory implements PaymentFactory {
    PaymentProcessor createProcessor() { return new UPIProcessor(); } // locked!
}

// RIGHT: family is compliance (tax + receipt + currency)
class IndiaComplianceFactory implements RegionalComplianceFactory {
    TaxCalculator createTaxCalc()     { return new IndiaTaxCalc(); }   // GST
    ReceiptGenerator createReceipt()  { return new IndiaReceipt(); }   // GST Invoice
    CurrencyFormatter createCurrency(){ return new IndiaFormatter(); }  // INR
}

// Payment method is INDEPENDENT -- Simple Factory
PaymentProcessor p = PaymentProcessorFactory.create("UPI");          // OR
PaymentProcessor p = PaymentProcessorFactory.create("CREDIT_CARD");  // India supports both!

// WITHOUT Factory Method: coupling + DUPLICATED orchestration
class OrderService {
    void send(String msg) {
        EmailNotification n = new EmailNotification(loadSmtp()); // coupled
        n.send(msg);
        log(msg);   // duplicated in PaymentService, ShippingService...
        audit();     // duplicated everywhere
    }
}

// WITH Factory Method: orchestration written ONCE
abstract class NotificationService {
    abstract Notification createNotification(); // hook
    final void send(String msg) {        // ONCE
        Notification n = createNotification();
        n.send(msg);
        log(msg);    // NOT duplicated
        audit();     // NOT duplicated
    }
}
// Value isn't removing 'new' -- it's protecting shared logic.

@Service("upi")
class UPIPaymentService implements PaymentService { ... }

@Service("creditcard")
class CreditCardPaymentService implements PaymentService { ... }

// Spring auto-populates Map with ALL PaymentService beans
@Autowired Map<String, PaymentService> services;
// Map = {"upi": UPIPaymentService, "creditcard": CreditCardPaymentService}

@PostMapping("/pay")
void pay(@RequestBody PayRequest req) {
    // User clicks "UPI" -> req.getMethod() = "upi"
    PaymentService svc = services.get(req.getMethod()); // runtime!
    svc.process(req.getAmount()); // no 'new' anywhere
}

// Simple Factory: ONE class, switch/if-else, ONE product type
Notification n = NotificationFactory.create(type); // 80% of cases

// Factory Method: abstract hook in service, subclass creates
abstract class NotificationService {
    abstract Notification createNotification(); // hook
    void send(String msg) { /* shared workflow */ }
}
class EmailService extends NotificationService { /* fills hook */ }

// Abstract Factory: interface with MULTIPLE create methods, FAMILIES
interface PaymentFactory {
    PaymentProcessor createProcessor();  // product 1
    Receipt createReceipt();              // product 2
    PaymentValidator createValidator();   // product 3
}
// IndiaPaymentFactory returns consistent India family

// SEPARATE CLASS: multiple services need creation (DRY)
class NotificationFactory { // used by Order, Payment, Shipping...
    static Notification create(Type t) { ... }
}
// Test: "Does another class also create this?" YES -> separate class

// METHOD IN SERVICE: only THIS class creates AND uses
abstract class PaymentService {
    abstract PaymentProcessor createProcessor(); // only here
    void process(double amt) {
        PaymentProcessor p = createProcessor();
        p.charge(amt);
        log(); audit(); // shared logic justifies the class
    }
}
// Test: "If creation changes, does business logic ALSO change?" YES -> same class

